var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"조금 진정됐어?","JPN":"少しは落ち着いたか？","ENG":"Feeling better?","TWN":"冷靜下來了嗎？"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"마셔. 술이라고 있는 게 순 보드카뿐이더군.","JPN":"飲め。ここにはウォッカしかないみたいだが。","ENG":"Here. Vodka was the only drink I could find.","TWN":"喝吧，我只找到伏特加。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몽타뉴.","JPN":"モンターニュ。","ENG":"Montagne.","TWN":"蒙塔妮。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"술 마셔도 되는 나이냐고 묻지는 마.","JPN":"酒を飲める歳かどうかは聞くな。","ENG":"Don't ask if I'm of legal age to drink.","TWN":"不要問我的年紀可以喝酒嗎。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"외견은 이래도 일단은 성인이야. 동면 조치 중에도 시간은 흐르거든.","JPN":"見た目はともかく一応成人だ。冬眠中でも時間は流れる。","ENG":"I might look like this, but I'm an adult. Time passes even when you're frozen in cryostasis.","TWN":"別看我長這樣，我已經是成年人了，畢竟在冬眠時時間也不會因此停止。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래. 네가 여기서 나타나도 이상하지 않긴 하네.","JPN":"そう。君がここで現れてもおかしくはないよね。","ENG":"Right. I guess it's not so weird that you're here.","TWN":"也是，你在這裡出現沒什麼好奇怪的。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"헛소리를 하는군. 당연히 이상하지.","JPN":"ふざけたことを。何がおかしくないだ。","ENG":"Nonsense. Of course it's weird.","TWN":"你在說什麼？很奇怪吧。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"벌레처럼 죽이려 들더니 이딴 열차에 처박아 둔다고?","JPN":"私を虫のように殺そうとしてきたと思えば、こんな列車に閉じ込めて。","ENG":"First you try to kill me like I'm some bug, and now you stick me in a crappy train?","TWN":"你之前明明恨不得把我殺掉，現在卻把我塞進這麼一台列車裡？"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"충분히 가지고 놀지 못한 게 얼마나 강한 인상이 들었길래?","JPN":"私で遊び尽くせなかったことが、そんなに悔しかったのか？","ENG":"Were you holding a grudge from not harassing me enough?","TWN":"沒能盡情玩弄我是給你留下多大的遺憾？"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로가 아니라, 나 때문이겠지.","JPN":"きっとマエストロじゃなくて、私のせいね。","ENG":"It's probably because of me, not Maestra.","TWN":"不是指揮家，是因為我的關係吧。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네 말이 맞았어. 레아 슈나이더는 네퀴티아였으니까.","JPN":"君の言ったとおりだった。レア・シュナイダーはネキティアだったよ。","ENG":"You were right. Because Leah Schneider was Nequitia.","TWN":"不過你說的也沒錯，因為蕾亞·修奈德就是莉奎蒂亞。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"술이 들어가니 말이 통하는군.","JPN":"酒が入って、やっと話が通じたか。","ENG":"The vodka's helping you open up, I see.","TWN":"喝了酒後，終於能正常對話了。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"진즉 그렇게 나왔으면 서로 피곤할 것 없었잖아.","JPN":"最初からそうだったら、お互い楽だったのに。","ENG":"It could've saved us a lot of time if you started out like that.","TWN":"你早這麼說的話，我們也不需要彼此折磨。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나는 아무것도 몰랐어. 이렇게 말한다고 네가 납득할 리 없겠지만.","JPN":"私は何も知らなかったの。それを今更言ったところで君は納得しないだろうけど。","ENG":"I wasn't aware. Not that I expect you to believe me, though.","TWN":"你可能無法接受，但我那時候真的什麼都不知道。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"알아. 네가 몰랐다는 거.","JPN":"お前が何も知らないということはわかっていた。","ENG":"I know that you weren't aware.","TWN":"我知道你不知道。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만 그걸 인정해 버리면 죽어 버린 내 전우들은?","JPN":"でもそれを認めてしまったら、死んでしまった私の戦友はどうなる？","ENG":"But if I admit that, what about my dead comrades?","TWN":"只是要是我承認的話，我那些犧牲的戰友情何以堪？"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"돼지 흉내를 내면서 기어다니다가 죽은 우리 오빠는?","JPN":"豚よろしく四足で這いまわったあげく殺された兄さんは？","ENG":"What about my brother, who died after crawling on the floor like a pig?","TWN":"我那模仿豬在地上爬後死去的哥哥又該情何以堪？"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그 사람들은 누구를 원망해야 했지?","JPN":"あの人たちは誰を恨めばいい？","ENG":"Who were they supposed to blame?","TWN":"那些人該怨誰才好？"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};